// Extraire les établissements de la réponse Sirene
const etablissements = $input.first().json.etablissements || [];

return etablissements.map(etab => {
  const uniteLegale = etab.uniteLegale || {};
  const adresse = etab.adresseEtablissement || {};

  // Nettoyer les valeurs [ND]
  const cleanValue = (value) => {
    if (!value || value === '[ND]' || value === 'ND') return null;
    return value;
  };

  // Construire le nom
  let name = cleanValue(uniteLegale.denominationUniteLegale);
  if (!name) {
    const prenom = cleanValue(uniteLegale.prenom1UniteLegale);
    const nom = cleanValue(uniteLegale.nomUniteLegale);
    name = prenom && nom ? `${prenom} ${nom}` : (prenom || nom || 'Entreprise');
  }

  // Construire l'adresse
  const addressParts = [
    cleanValue(adresse.numeroVoieEtablissement),
    cleanValue(adresse.typeVoieEtablissement),
    cleanValue(adresse.libelleVoieEtablissement),
    cleanValue(adresse.codePostalEtablissement),
    cleanValue(adresse.libelleCommuneEtablissement)
  ].filter(Boolean);

  return {
    json: {
      siret: etab.siret,
      siren: etab.siren,
      name: name,
      address: addressParts.join(' '),
      city: cleanValue(adresse.libelleCommuneEtablissement) || '',
      postcode: cleanValue(adresse.codePostalEtablissement) || '',
      sector: cleanValue(uniteLegale.activitePrincipaleUniteLegale) || '',
      email: null
    }
  };
});

// Récupérer les données de Pappers (chaque item est une réponse Pappers)
const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const pappersData = items[i].json;

  // Extraire l'email depuis Pappers (peut être dans différents champs)
  let email = null;
  let phone = null;
  let website = null;

  // Chercher l'email dans les différents champs possibles
  if (pappersData.email) {
    email = pappersData.email;
  } else if (pappersData.siege && pappersData.siege.email) {
    email = pappersData.siege.email;
  } else if (pappersData.etablissement_siege && pappersData.etablissement_siege.email) {
    email = pappersData.etablissement_siege.email;
  }

  // Chercher le téléphone
  if (pappersData.telephone) {
    phone = pappersData.telephone;
  } else if (pappersData.siege && pappersData.siege.telephone) {
    phone = pappersData.siege.telephone;
  }

  // Chercher le site web
  if (pappersData.site_web) {
    website = pappersData.site_web;
  } else if (pappersData.siege && pappersData.siege.site_web) {
    website = pappersData.siege.site_web;
  }

  // Construire le nom de l'entreprise
  let name = pappersData.nom_entreprise || pappersData.denomination || 'Entreprise';

  // Construire l'adresse
  let address = '';
  if (pappersData.siege) {
    const s = pappersData.siege;
    address = [s.adresse_ligne_1, s.code_postal, s.ville].filter(Boolean).join(' ');
  }

  results.push({
    json: {
      siret: pappersData.siege?.siret || pappersData.siret || '',
      siren: pappersData.siren || '',
      name: name,
      address: address,
      city: pappersData.siege?.ville || '',
      postcode: pappersData.siege?.code_postal || '',
      sector: pappersData.code_naf || pappersData.libelle_code_naf || '',
      email: email,
      phone: phone,
      website: website
    }
  });
}

return results;
